string removeOuterParentheses(const string &s) {
    string result;
    int depth = 0;

    for (char ch : s) {
        if (ch == '(') {
            if (depth > 0) result += ch;
            depth++;
        } else {
            depth--;
            if (depth > 0) result += ch;
        }
    }
    return result;
}

