code.C:
void removeOuterParentheses(char *s, char *result) {
    int depth = 0;
    int idx = 0; // index for result

    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '(') {
            if (depth > 0) result[idx++] = '(';
            depth++;
        } else {
            depth--;
            if (depth > 0) result[idx++] = ')';
        }
    }
    result[idx] = '\0'; // null-terminate
}

